SELECT first_name
FROM patients
WHERE date_of_death IS NULL;

SELECT sex, COUNT(patient_id) AS patient_count
FROM patients
GROUP BY sex;

SELECT COUNT(DISTINCT patient_id) AS total_patients_with_et
FROM comorbidities
WHERE comorbidity_name = 'Et';

SELECT COUNT(DISTINCT patient_id) AS distinct_patients_with_riluzole
FROM treatments
WHERE riluzole = 1;

SELECT COUNT(DISTINCT patient_id) AS num_patients_with_als
FROM diagnoses
WHERE diagnosis = 'ALS';

SELECT AVG(STRFTIME('%J', treatment_stop) - STRFTIME('%J', treatment_start)) AS average_duration
FROM treatments
WHERE patient_id = 1;

SELECT AVG(JULIANDAY(treatment_stop) - JULIANDAY(treatment_start)) AS average_treatment_duration
FROM treatments
WHERE treatment_name = 'ALS Treatment';

SELECT AVG(julianday(treatment_stop) - julianday(treatment_start)) AS average_days_treated
FROM treatments
WHERE treatment_name = 'ALS';

SELECT COUNT(patient_id) AS number_of_patients_with_penicillin_allergy
FROM patient_allergies
WHERE allergy_name = 'Penicillin';

SELECT COUNT(DISTINCT patient_id) AS unique_patients_with_als
FROM diagnoses
WHERE diagnosis = 'ALS';

SELECT diagnosis, COUNT(diagnosis_id) AS diagnosis_count
FROM diagnoses
GROUP BY diagnosis;

SELECT COUNT(patient_id) AS number_of_riluzole_users
FROM treatments
WHERE riluzole = 1;

SELECT COUNT(patient_id) AS total_patients_with_arf
FROM comorbidities
WHERE comorbidity_name = 'Arf';

SELECT COUNT(DISTINCT v.patient_id) AS unique_patient_count
FROM visits v
WHERE v.visit_type = 'Outpatient';
